/* Swiper fallback shim for legacy cached HTML references. */
(function (window) {
  if (typeof window === 'undefined') return;
  if (typeof window.Swiper === 'function') return;

  function Swiper() {
    return {
      destroy: function () {},
      update: function () {}
    };
  }

  window.Swiper = Swiper;
})(window);
